VALUES
  ('real-estate-moex-02812', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關留置權之敘述，何者錯誤？', '["稱留置權者，謂債權人占有他人之動產，而其債權之發生與該動產有牽連關係，於債權已屆清償期而未 受清償時，得留置該動產之權", "債權人於其債權已屆清償期而未受清償者，得定一個月以上之相當期限，通知債權人，聲明如不於其期 限內為清償時，即就其留置物取償", "債權人於其債權未屆清償期前，縱債務人無支付能力，債權人亦不得行使留置權", "債權人於其債權未受全部清償前，得就留置物之全部，行使其留置權。但留置物為可分者，僅得依其債 權與留置物價值之比例行使之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02813', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關限定繼承之敘述何者正確？', '["繼承人有數人者，為限定繼承時，應全體共同為之", "為限定繼承者，得於償還債務前，對受遺贈人交付遺贈", "限定繼承人以因繼承所得之遺產，償還被繼承人之債務", "繼承人雖隱匿遺產情節重大，仍得為限定繼承"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02814', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承人拋棄繼承應於知悉其得繼承之日起多久時間內，以書面向法院為之？', '["3個月", "4個月", "5個月", "6個月"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02815', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非屬公同共有？', '["遺產", "合夥財產", "夫妻共同財產", "夫或妻職業上所必需之物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02816', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲需錢孔急，向乙銀行借貸新台幣 5000 萬元，乙要求甲提供擔保；甲乃以其母丙名下市價約新台幣 2000 萬元之房屋一棟、其父丁之市值約新台幣3000萬元之土地一筆，及其兄戊之市值約新台幣1500萬元之店面 一間，設定共同抵押權與乙，且未限定各個抵押物應負擔之金額。問：各抵押物對乙之債權應分擔之金額應 如何計算？', '["依各抵押物價值之比例", "由債權人乙任意選擇", "依各抵押物價值，價值最低者先抵償之", "依各抵押物價值，價值最高者先抵償之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02817', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲17歲因對房地產深感興趣，於參觀乙建設公司推出之建案時，向乙謊稱其為年約26歲之竹科新貴，向乙 訂購房屋一戶並預付新台幣1萬元訂金。問：甲、乙之買賣契約效力如何？', '["有效", "無效", "效力未定", "甲之法定代理人得以甲尚未成年為由撤銷該契約"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02818', 'real-estate', 'real-estate-moex-097-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列敘述，何者錯誤？', '["盜贓或遺失物，如占有人係經由拍賣善意買得者，該物之所有權人須償還其支出之價金，才得回復其物", "盜贓或遺失物，如占有人係由公共市場善意買得者，該物之所有權人非償還其支出之價金，不得回復其 物", "盜贓或遺失物，如係金錢，不得向其善意占有人，請求回復", "盜贓或遺失物，如係無記名證券，該證券之所有權人無須支付價金，即得向其善意占有人，請求回復"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:14+00:00", "source_pdf_sha1": "b30ff99d1c37", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
